import fs from 'fs'; import path from 'path'; import axios from 'axios'; import { downloadContentFromMessage } from '@whiskeysockets/baileys'; const TMP_DIR = path.join(process.cwd(), 'tmp', 'grouppp'); if (!fs.existsSync(TMP_DIR)) fs.mkdirSync(TMP_DIR, { recursive: true }); export default { name: "setgpp", alias: ["setgrouppic", "setgroupicon", "gpp"], category: "group", description: "Change group profile picture", async execute(sock, m, args, PREFIX, extra) { const chatId = m.key.remoteJid; const isGroup = chatId.endsWith('@g.us'); if (!isGroup) { return sock.sendMessage(chatId, { text: `в”Ңв”Җв§ӯ *GROUP ONLY* рҹ‘Ҙ в§ӯв”Җв”җ в”Ӯ в”ңв”Җв§ӯ This command only works in groups! в”Ӯ в””в”Җв§ӯрҹҰҠ` }, { quoted: m }); } try { const groupMetadata = await sock.groupMetadata(chatId); const participants = groupMetadata.participants; const senderId = m.key.participant || chatId; const isSenderAdmin = participants.find(p => p.id === senderId)?.admin === 'admin' || participants.find(p => p.id === senderId)?.admin === 'superadmin'; if (!isSenderAdmin && !m.key.fromMe) { return sock.sendMessage(chatId, { text: `в”Ңв”Җв§ӯ *ADMIN ONLY* рҹ‘‘ в§ӯв”Җв”җ в”Ӯ в”ңв”Җв§ӯ Only admins can change group icon! в”Ӯ в””в”Җв§ӯрҹҰҠ` }, { quoted: m }); } const isBotAdmin = participants.find(p => p.id === sock.user.id)?.admin === 'admin' || participants.find(p => p.id === sock.user.id)?.admin === 'superadmin'; if (!isBotAdmin) { return sock.sendMessage(chatId, { text: `в”Ңв”Җв§ӯ *BOT NOT ADMIN* вқҢ в§ӯв”Җв”җ в”Ӯ в”ңв”Җв§ӯ I need to be an admin to change group icon! в”Ӯ в””в”Җв§ӯрҹҰҠ` }, { quoted: m }); } let imageBuffer = null; if (args[0] && args[0].startsWith('http')) { const response = await axios.get(args[0], { responseType: 'arraybuffer' }); imageBuffer = Buffer.from(response.data); } const quoted = m.message?.extendedTextMessage?.contextInfo?.quotedMessage; if (quoted?.imageMessage) { const stream = await downloadContentFromMessage(quoted.imageMessage, 'image'); let buffer = Buffer.alloc(0); for await (const chunk of stream) { buffer = Buffer.concat([buffer, chunk]); } imageBuffer = buffer; } if (!imageBuffer) { return sock.sendMessage(chatId, { text: `в”Ңв”Җв§ӯ *SET GROUP PIC* рҹ–јпёҸ в§ӯв”Җв”җ в”Ӯ в”ңв”Җв§ӯ *Usage:* в”Ӯ вҖў Reply to an image в”Ӯ вҖў Provide image URL в”Ӯ в”ңв”Җв§ӯ *Examples:* в”Ӯ вҖў Reply to image вҶ’ ${PREFIX}setgpp в”Ӯ вҖў ${PREFIX}setgpp https://example.com/image.jpg в”Ӯ в””в”Җв§ӯрҹҰҠ` }, { quoted: m }); } const filePath = path.join(TMP_DIR, `grouppp_${Date.now()}.jpg`); fs.writeFileSync(filePath, imageBuffer); await sock.updateProfilePicture(chatId, { url: filePath }); fs.unlinkSync(filePath); await sock.sendMessage(chatId, { text: `в”Ңв”Җв§ӯ *вң… GROUP ICON UPDATED* в§ӯв”Җв”җ в”Ӯ в”ңв”Җв§ӯ *Group:* ${groupMetadata.subject} в”ңв”Җв§ӯ *Updated by:* ${m.pushName || 'Admin'} в”Ӯ в”Ӯ рҹ–јпёҸ New look for the group! в”Ӯ в””в”Җв§ӯрҹҰҠ` }, { quoted: m }); } catch (error) { console.error('Setgpp error:', error); await sock.sendMessage(chatId, { text: `в”Ңв”Җв§ӯ *UPDATE FAILED* вқҢ в§ӯв”Җв”җ в”Ӯ в”ңв”Җв§ӯ ${error.message} в”Ӯ в”ңв”Җв§ӯ *Possible reasons:* в”Ӯ вҖў Invalid image в”Ӯ вҖў Bot not admin в”Ӯ вҖў Image too large в”Ӯ в””в”Җв§ӯрҹҰҠ` }, { quoted: m }); } } };